const NEXTJS_TEMPLATE = (name, features) => ({
  'package.json': JSON.stringify({
    name, version: '1.0.0', scripts: { dev: 'next dev', build: 'next build', start: 'next start' },
    dependencies: { next: '^14.2.0', react: '^18.3.1', 'react-dom': '^18.3.1' },
  }, null, 2),
  'next.config.mjs': `/** @type {import('next').NextConfig} */\nconst nextConfig = {};\nexport default nextConfig;`,
  'app/layout.js': `import './globals.css';\nexport const metadata = { title: '${name}', description: 'Built by PromptHouse Evo Studio' };\nexport default function RootLayout({ children }) {\n  return <html lang="en"><body>{children}</body></html>;\n}`,
  'app/globals.css': `* { margin: 0; padding: 0; box-sizing: border-box; }\n:root { --bg: #09090b; --surface: #18181b; --border: #27272a; --text: #fafafa; --primary: #8b5cf6; }\nbody { background: var(--bg); color: var(--text); font-family: system-ui, sans-serif; }`,
  'app/page.js': `export default function Home() {\n  return (\n    <main style={{ padding: 32 }}>\n      <h1 style={{ fontSize: 32, fontWeight: 800 }}>${name}</h1>\n      <p style={{ color: '#a1a1aa', marginTop: 8 }}>Built by PromptHouse Evo Studio</p>\n      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: 16, marginTop: 24 }}>\n        ${features.map(f => `<div style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: 16, padding: 24 }}>\n          <h3>${pascal(f)}</h3>\n          <p style={{ color: '#71717a', marginTop: 8, fontSize: 14 }}>Production-ready ${f} module</p>\n        </div>`).join('\n        ')}\n      </div>\n    </main>\n  );\n}`,
  ...Object.fromEntries(features.map(f => [
    `app/${f}/page.js`,
    `export default function ${pascal(f)}Page() {\n  return (\n    <main style={{ padding: 32 }}>\n      <h1 style={{ fontSize: 28, fontWeight: 800 }}>${pascal(f)}</h1>\n      <p style={{ color: '#a1a1aa', marginTop: 8 }}>Production-ready ${f} module</p>\n    </main>\n  );\n}`
  ])),
});

function pascal(s) {
  return s.replace(/(^|[-_ ])(\w)/g, (_, __, c) => c.toUpperCase());
}

