// AUTONOMOUS BUILD PIPELINE
// ═══════════════════════════════════════════════════════════

export const APP_TYPES = [
  { id: 'flutter', name: 'Flutter App', icon: '📱', desc: 'Cross-platform mobile + desktop' },
  { id: 'react', name: 'React Web App', icon: '⚛️', desc: 'Vite + React SPA' },
  { id: 'nextjs', name: 'Next.js App', icon: '▲', desc: 'Full-stack React framework' },
];

export function generateApp(type, name, featuresStr) {
  const features = featuresStr.split(',').map(f => f.trim().toLowerCase().replace(/\s+/g, '_')).filter(Boolean);
  const cleanName = name.trim().toLowerCase().replace(/\s+/g, '_') || 'my_app';

  switch (type) {
    case 'flutter': return { files: FLUTTER_TEMPLATE(cleanName, features), type: 'flutter', name: cleanName, features };
    case 'react': return { files: REACT_TEMPLATE(cleanName, features), type: 'react', name: cleanName, features };
    case 'nextjs': return { files: NEXTJS_TEMPLATE(cleanName, features), type: 'nextjs', name: cleanName, features };
    default: return { files: REACT_TEMPLATE(cleanName, features), type: 'react', name: cleanName, features };
  }
}

// ═══════════════════════════════════════════════════════════
// BOT COLLABORATION SIMULATION
// ═══════════════════════════════════════════════════════════

export function runBotPipeline(mission, type, name, features) {
  const lead = selectLead(mission);
  const app = generateApp(type, name, features);
  const fileCount = Object.keys(app.files).length;

  const timeline = [
    { bot: 'evo', action: 'intake', message: `Mission received. Generating ${type} app: "${name}". ${fileCount} files will be built.`, expression: 'focused', motion: 'speaking' },
    { bot: 'conductor', action: 'route', message: `Route mapped: intake → scaffold → build → audit → gate. Lead: ${lead.name}. Activating Dev and Builder.`, expression: 'focused', motion: 'gesturing' },
    { bot: 'companion', action: 'translate', message: `Features parsed: [${app.features.join(', ')}]. Stack: ${type}. Mapping to build artifacts.`, expression: 'happy', motion: 'speaking' },
    { bot: 'dev', action: 'code', message: `Code generation: ${fileCount} files locked. Architecture: feature-first. State: Riverpod/React hooks. Routing: go_router/react-router.`, expression: 'focused', motion: 'typing' },
    { bot: 'builder', action: 'build', message: `Artifacts constructed. All ${fileCount} files generated. No stubs, no TODOs, no placeholders. Real code only.`, expression: 'happy', motion: 'building' },
    { bot: 'verifier', action: 'audit', message: `Audit complete. File count: ${fileCount}. All files contain executable code. No dead routes. Gate: PASS.`, expression: 'happy', motion: 'scanning' },
    { bot: 'ledger', action: 'classify', message: `Truth state: BUILT. Canon updated. All ${fileCount} artifacts classified as production-ready.`, expression: 'neutral', motion: 'gesturing' },
    { bot: 'memory', action: 'archive', message: `Session logged. App "${name}" archived in canon. Thread preserved for continuity.`, expression: 'neutral', motion: 'idle' },
    { bot: 'heartbeat', action: 'status', message: `Build complete. ${fileCount} files. 0 errors. Ready for deployment.`, expression: 'celebrating', motion: 'celebrating' },
    { bot: 'enterprise auth', action: 'lock', message: `Ownership confirmed. You built this. You own this. Deploy when ready.`, expression: 'happy', motion: 'gesturing' },
    { bot: 'evo', action: 'ship', message: `✅ ${name} — ${type} app — ${fileCount} files — SHIPPED. Download ready.`, expression: 'celebrating', motion: 'celebrating' },
  ];

  return { app, lead, timeline, fileCount };
}

// ═══════════════════════════════════════════════════════════
// DOWNLOAD AS ZIP
// ═══════════════════════════════════════════════════════════

export async function downloadAsZip(app) {
  // ✨ Enterprise Handoff — Certificate of Truth
  const certificate = {
    manifestId: `PH-EVO-${Math.random().toString(36).slice(2, 9).toUpperCase()}`,
    timestamp: new Date().toISOString(),
    governance: {
      canon: 'Enterprise V3',
      lead: BOT_ROSTER[0].name,
      auditor: 'Verifier (Owl)',
      truthState: 'verified'
    },
    auditLog: [
      { bot: 'Evo', action: 'ANCHOR', status: 'PASS' },
      { bot: 'Dev', action: 'BUILD', status: 'PASS' },
      { bot: 'Verifier', action: 'VERIFY', status: 'PASS' },
      { bot: 'Boundary', action: 'ENFORCE', status: 'PASS' }
    ],
    signatures: BOT_ROSTER.map(b => ({ bot: b.name, sig: `SIG_${Math.random().toString(36).slice(2, 10)}` }))
  };

  const files = [
    ...Object.entries(app.files).map(([path, content]) => ({ path, content })),
    { path: 'handoff-certificate.json', content: JSON.stringify(certificate, null, 2) }
  ];

  const zipContent = files.map(f => `FILE: ${f.path}\n\n${f.content}\n\n${'='.repeat(40)}`).join('\n\n');
  const blob = new Blob([zipContent], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${app.name}_production_build.txt`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// Individual file download
export function downloadFile(filename, content) {
  const blob = new Blob([content], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename.replace(/\//g, '_');
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// ═══════════════════════════════════════════════════════════
// WRITE TO LOCAL DISK (CLI BRIDGE)
// ═══════════════════════════════════════════════════════════

export async function writeToLocalDisk(app) {
  try {
    const response = await fetch('http://localhost:3001/build', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        appName: app.name,
        files: app.files
      })
    });
    
    if (!response.ok) {
      throw new Error(`Server returned ${response.status}`);
    }
    
    const result = await response.json();
    if (!result.success) {
      throw new Error(result.error || 'Unknown error');
    }
    
    return result;
  } catch (err) {
    console.error('Failed to write to local disk via bridge:', err);
    throw new Error('Could not connect to CLI bridge. Make sure "npm run bridge" is running.');
  }
}

